// ========== HELPERS ==========
function ksh(n) {
  if (n >= 1000000) return 'KSh ' + (n/1000000).toFixed(1) + 'M';
  if (n >= 1000) return 'KSh ' + (n/1000).toFixed(1) + 'K';
  return 'KSh ' + n.toLocaleString();
}
function kshFull(n) { return 'KSh ' + n.toLocaleString(); }
function getFilteredTx() {
  if (currentMonth === 'all') return transactions;
  return transactions.filter(t => t.month === currentMonth);
}
function getCatSummary(txs) {
  const cats = {};
  for (const t of txs) {
    if (!cats[t.category]) cats[t.category] = { exp: 0, rev: 0, count: 0 };
    cats[t.category].exp += t.expenditure;
    cats[t.category].rev += t.revenue;
    cats[t.category].count++;
  }
  return cats;
}
function getDaysInPeriod(txs) {
  if (!txs.length) return 1;
  const dates = txs.map(t => t.date).sort();
  const d1 = new Date(dates[0]), d2 = new Date(dates[dates.length-1]);
  return Math.max(1, Math.round((d2-d1)/(1000*60*60*24))+1);
}
function formatDate(d) { return new Date(d).toLocaleDateString('en-KE',{day:'2-digit',month:'short',year:'numeric'}); }

// ========== PAGE NAVIGATION ==========
const pages = {
  overview: 'Overview',
  transactions: 'Transactions',
  categories: 'Categories',
  insights: 'Insights',
  add: 'Add Transaction'
};
function showPage(id, el) {
  document.querySelectorAll('.page').forEach(p => p.classList.remove('active'));
  document.querySelectorAll('.nav-item').forEach(n => n.classList.remove('active'));
  document.getElementById('page-' + id).classList.add('active');
  if (el) el.classList.add('active');
  document.getElementById('page-title').textContent = pages[id];
  renderCurrentPage(id);
}
function renderCurrentPage(id) {
  if (id === 'overview') renderOverview();
  else if (id === 'transactions') renderTransactions();
  else if (id === 'categories') renderCategories();
  else if (id === 'insights') renderInsights();
  else if (id === 'add') renderAdded();
}
function setMonth(m, el) {
  currentMonth = m;
  document.querySelectorAll('.month-pill').forEach(p => p.classList.remove('active'));
  el.classList.add('active');
  const activePage = document.querySelector('.page.active');
  if (activePage) renderCurrentPage(activePage.id.replace('page-',''));
}

// ========== OVERVIEW ==========
function renderOverview() {
  const txs = getFilteredTx();
  const totalExp = txs.reduce((s,t)=>s+t.expenditure,0);
  const totalRev = txs.reduce((s,t)=>s+t.revenue,0);
  const totalTc = txs.reduce((s,t)=>s+t.transactionCost,0);
  const net = totalRev - totalExp;

  const grid = document.getElementById('stats-grid');
  grid.innerHTML = `
    <div class="stat-card" style="--card-color:var(--red)">
      <div class="label">Total Expenditure</div>
      <div class="value" style="color:var(--red)">${ksh(totalExp)}</div>
      <div class="sub">${txs.filter(t=>t.expenditure>0).length} transactions</div>
    </div>
    <div class="stat-card" style="--card-color:var(--green)">
      <div class="label">Total Revenue</div>
      <div class="value" style="color:var(--green)">${ksh(totalRev)}</div>
      <div class="sub">${txs.filter(t=>t.revenue>0).length} transactions</div>
    </div>
    <div class="stat-card" style="--card-color:${net>=0?'var(--green)':'var(--red)'}">
      <div class="label">Net Balance</div>
      <div class="value" style="color:${net>=0?'var(--green)':'var(--red)'}">${net>=0?'+':''}${ksh(net)}</div>
      <div class="badge ${net>=0?'pos':'neg'}">${net>=0?'▲ Surplus':'▼ Deficit'}</div>
    </div>
    <div class="stat-card" style="--card-color:var(--warn)">
      <div class="label">Transaction Costs</div>
      <div class="value" style="color:var(--warn)">${ksh(totalTc)}</div>
      <div class="sub">${((totalTc/Math.max(1,totalExp))*100).toFixed(1)}% of expenditure</div>
    </div>
  `;

  renderMonthlyChart();
  renderDonut(txs);
  renderWeeklyChart(txs);
  renderRecent(txs);
}

function renderMonthlyChart() {
  const months = ['January','February','March','April'];
  const mData = months.map(m => {
    const txs = transactions.filter(t=>t.month===m);
    return {
      exp: txs.reduce((s,t)=>s+t.expenditure,0),
      rev: txs.reduce((s,t)=>s+t.revenue,0)
    };
  });
  const canvas = document.getElementById('monthlyChart');
  const ctx = canvas.getContext('2d');
  const W = canvas.parentElement.clientWidth - 48;
  canvas.width = W; canvas.height = 220;
  ctx.clearRect(0,0,W,220);

  const maxVal = Math.max(...mData.flatMap(d=>[d.exp,d.rev]));
  const barW = 48, gap = (W - months.length * barW * 2 - 40) / (months.length + 1);
  const chartH = 160, padTop = 20, padLeft = 20;

  months.forEach((m, i) => {
    const x = padLeft + gap * (i+1) + i * barW * 2;
    const expH = (mData[i].exp / maxVal) * chartH;
    const revH = (mData[i].rev / maxVal) * chartH;

    // Exp bar
    ctx.fillStyle = '#ff4d6d33';
    ctx.fillRect(x, padTop + chartH - expH, barW, expH);
    ctx.fillStyle = '#ff4d6d';
    ctx.fillRect(x, padTop + chartH - expH, barW, 3);

    // Rev bar
    ctx.fillStyle = '#00d4aa33';
    ctx.fillRect(x + barW + 4, padTop + chartH - revH, barW, revH);
    ctx.fillStyle = '#00d4aa';
    ctx.fillRect(x + barW + 4, padTop + chartH - revH, barW, 3);

    // Label
    ctx.fillStyle = '#8899b4';
    ctx.font = '11px Space Grotesk, sans-serif';
    ctx.textAlign = 'center';
    ctx.fillText(m.slice(0,3), x + barW, padTop + chartH + 16);
  });

  // Legend
  ctx.fillStyle = '#ff4d6d'; ctx.fillRect(W-140, 10, 10, 10);
  ctx.fillStyle = '#8899b4'; ctx.font = '11px Space Grotesk'; ctx.textAlign = 'left';
  ctx.fillText('Expenditure', W-126, 19);
  ctx.fillStyle = '#00d4aa'; ctx.fillRect(W-50, 10, 10, 10);
  ctx.fillText('Revenue', W-36, 19);
}

function renderDonut(txs) {
  const cats = getCatSummary(txs);
  const sorted = Object.entries(cats).sort((a,b)=>b[1].exp-a[1].exp).slice(0,6);
  const total = sorted.reduce((s,[,v])=>s+v.exp,0);

  const canvas = document.getElementById('donutChart');
  const ctx = canvas.getContext('2d');
  ctx.clearRect(0,0,160,160);
  
  let start = -Math.PI/2;
  const cx = 80, cy = 80, r = 70, inner = 48;

  sorted.forEach(([cat, data]) => {
    const slice = (data.exp / total) * 2 * Math.PI;
    ctx.beginPath();
    ctx.moveTo(cx, cy);
    ctx.arc(cx, cy, r, start, start + slice);
    ctx.closePath();
    ctx.fillStyle = catColor(cat);
    ctx.fill();
    start += slice;
  });

  // Inner hole
  ctx.beginPath();
  ctx.arc(cx, cy, inner, 0, 2*Math.PI);
  ctx.fillStyle = '#12161e';
  ctx.fill();

  document.getElementById('donut-center-val').textContent = ksh(total);

  const legend = document.getElementById('donut-legend');
  legend.innerHTML = sorted.map(([cat, data]) => `
    <div class="legend-item">
      <div style="display:flex;align-items:center;flex:1;gap:6px;min-width:0">
        <div class="legend-dot" style="background:${catColor(cat)}"></div>
        <span class="legend-name" style="overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${cat}</span>
      </div>
      <span class="legend-val">${ksh(data.exp)}</span>
    </div>
  `).join('');
}

function renderWeeklyChart(txs) {
  // Group by day of month for the selected period
  const byDay = {};
  txs.forEach(t => {
    const day = t.date.slice(8,10);
    if (!byDay[day]) byDay[day] = { exp: 0, rev: 0 };
    byDay[day].exp += t.expenditure;
    byDay[day].rev += t.revenue;
  });

  const canvas = document.getElementById('weeklyChart');
  const ctx = canvas.getContext('2d');
  const W = canvas.parentElement.clientWidth - 48;
  canvas.width = W; canvas.height = 220;
  ctx.clearRect(0, 0, W, 220);

  const days = Object.keys(byDay).sort().slice(-14); // last 14 days
  if (!days.length) return;

  const maxVal = Math.max(...days.flatMap(d=>[byDay[d].exp, byDay[d].rev]), 1);
  const barW = Math.max(8, (W - 40) / days.length / 2 - 2);
  const chartH = 160, padTop = 10, padLeft = 10;

  days.forEach((day, i) => {
    const x = padLeft + i * (barW * 2 + 4);
    const expH = (byDay[day].exp / maxVal) * chartH;
    const revH = (byDay[day].rev / maxVal) * chartH;

    if (expH > 0) {
      ctx.fillStyle = 'rgba(255,77,109,0.7)';
      ctx.fillRect(x, padTop + chartH - expH, barW, expH);
    }
    if (revH > 0) {
      ctx.fillStyle = 'rgba(0,212,170,0.7)';
      ctx.fillRect(x + barW + 2, padTop + chartH - revH, barW, revH);
    }

    if (i % 3 === 0) {
      ctx.fillStyle = '#4a5568';
      ctx.font = '9px JetBrains Mono, monospace';
      ctx.textAlign = 'center';
      ctx.fillText(day, x + barW, padTop + chartH + 14);
    }
  });
}

function renderRecent(txs) {
  const recent = [...txs].sort((a,b)=>b.date.localeCompare(a.date)).slice(0,8);
  const el = document.getElementById('recent-list');
  el.innerHTML = recent.map(t => `
    <div style="display:flex;align-items:center;justify-content:space-between;padding:8px 0;border-bottom:1px solid var(--border)">
      <div>
        <div style="font-size:12px;font-weight:500;color:var(--text)">${t.description.slice(0,28)}</div>
        <div style="font-size:10px;color:var(--text3);margin-top:2px">${t.date} · <span style="color:${catColor(t.category)}">${t.category}</span></div>
      </div>
      <div class="${t.expenditure > 0 && t.revenue === 0 ? 'type-exp' : 'type-rev'}" style="font-size:12px">
        ${t.expenditure > 0 && t.revenue === 0 ? '-'+ksh(t.expenditure) : '+'+ksh(t.revenue)}
      </div>
    </div>
  `).join('');
}

// ========== TRANSACTIONS ==========
function renderTransactions() {
  const txs = getFilteredTx();
  const search = document.getElementById('tx-search').value.toLowerCase();
  const catF = document.getElementById('tx-cat-filter').value;
  const typeF = document.getElementById('tx-type-filter').value;

  // Populate cat filter
  const cats = [...new Set(transactions.map(t=>t.category))].sort();
  const catSel = document.getElementById('tx-cat-filter');
  if (catSel.options.length === 1) {
    cats.forEach(c => { const o = document.createElement('option'); o.value=c; o.textContent=c; catSel.appendChild(o); });
  }

  let filtered = txs.filter(t => {
    if (catF && t.category !== catF) return false;
    if (typeF && t.type !== typeF) return false;
    if (search && !t.description.toLowerCase().includes(search) && !t.category.toLowerCase().includes(search)) return false;
    return true;
  });

  filtered.sort((a,b) => b.date.localeCompare(a.date));
  const total = filtered.length;
  const totalPages = Math.max(1, Math.ceil(total / TX_PER_PAGE));
  if (txPage > totalPages) txPage = 1;
  const start = (txPage-1) * TX_PER_PAGE;
  const page = filtered.slice(start, start + TX_PER_PAGE);

  document.getElementById('tx-count').textContent = `(${total} records)`;
  document.getElementById('tx-tbody').innerHTML = page.map(t => `
    <tr>
      <td class="date-cell">${t.date}</td>
      <td><span class="cat-badge" style="background:${catColor(t.category)}22;color:${catColor(t.category)}">${t.category}</span></td>
      <td class="desc-cell">${t.description}</td>
      <td class="${t.expenditure > 0 ? 'type-exp' : ''}">${t.expenditure > 0 ? kshFull(t.expenditure) : '-'}</td>
      <td class="${t.revenue > 0 ? 'type-rev' : ''}">${t.revenue > 0 ? kshFull(t.revenue) : '-'}</td>
      <td style="color:var(--text3);font-size:12px">${t.transactionCost > 0 ? kshFull(t.transactionCost) : '-'}</td>
      <td class="pm-cell">${t.paymentMethod}</td>
    </tr>
  `).join('');

  document.getElementById('page-info').textContent = `Showing ${start+1}–${Math.min(start+TX_PER_PAGE,total)} of ${total}`;
  
  const btnCont = document.getElementById('page-btns');
  btnCont.innerHTML = '';
  const prevBtn = document.createElement('button');
  prevBtn.className = 'page-btn'; prevBtn.textContent = '←'; prevBtn.disabled = txPage === 1;
  prevBtn.onclick = () => { txPage--; renderTransactions(); };
  btnCont.appendChild(prevBtn);
  
  const range = Math.min(totalPages, 5);
  let startP = Math.max(1, txPage - 2);
  let endP = Math.min(totalPages, startP + range - 1);
  startP = Math.max(1, endP - range + 1);
  for (let p = startP; p <= endP; p++) {
    const b = document.createElement('button');
    b.className = 'page-btn' + (p === txPage ? ' current' : '');
    b.textContent = p;
    b.onclick = (pp => () => { txPage = pp; renderTransactions(); })(p);
    btnCont.appendChild(b);
  }

  const nextBtn = document.createElement('button');
  nextBtn.className = 'page-btn'; nextBtn.textContent = '→'; nextBtn.disabled = txPage === totalPages;
  nextBtn.onclick = () => { txPage++; renderTransactions(); };
  btnCont.appendChild(nextBtn);
}

// ========== CATEGORIES ==========
function renderCategories() {
  const txs = getFilteredTx();
  const cats = getCatSummary(txs);
  const maxExp = Math.max(...Object.values(cats).map(v=>v.exp), 1);
  const sortedCats = Object.entries(cats).sort((a,b)=>b[1].exp-a[1].exp);

  const catIcons = {
    'Food':'🍽️','Bills':'⚡','Transport':'🚌','Paypal Services':'💳',
    'Friends & Family':'👨‍👩‍👧','Shopping':'🛒','Loans':'💸','Savings':'🏦',
    'Equity Account':'📈','Entertainment':'🎮','Home Appliance':'🏠',
    'Withdrawal':'💵','Clothings':'👕'
  };

  document.getElementById('cat-grid').innerHTML = sortedCats.map(([cat, data]) => {
    const pct = ((data.exp / maxExp) * 100).toFixed(0);
    const revPct = data.rev > 0 ? ((data.rev / Math.max(data.exp, data.rev)) * 100).toFixed(0) : 0;
    return `
      <div class="cat-card">
        <h4>
          <div class="cat-icon" style="background:${catColor(cat)}22">${catIcons[cat]||'📌'}</div>
          ${cat}
        </h4>
        <div class="progress-bar-outer">
          <div class="progress-bar-inner" style="width:${pct}%;background:${catColor(cat)};"></div>
        </div>
        <div class="cat-amounts">
          <span style="color:var(--red);font-size:12px;font-family:'JetBrains Mono',monospace">${data.exp > 0 ? '-'+ksh(data.exp) : 'KSh 0'}</span>
          <span style="color:var(--green);font-size:12px;font-family:'JetBrains Mono',monospace">${data.rev > 0 ? '+'+ksh(data.rev) : ''}</span>
        </div>
        <div style="font-size:11px;color:var(--text3);margin-top:6px">${data.count} transactions</div>
      </div>
    `;
  }).join('');

  const sel = document.getElementById('cat-detail-select');
  sel.innerHTML = sortedCats.map(([cat]) => `<option value="${cat}">${cat}</option>`).join('');
  renderCatDetail();
}

function renderCatDetail() {
  const cat = document.getElementById('cat-detail-select').value;
  const txs = getFilteredTx().filter(t => t.category === cat).sort((a,b)=>b.date.localeCompare(a.date));
  document.getElementById('cat-detail-tbody').innerHTML = txs.map(t => `
    <tr>
      <td class="date-cell">${t.date}</td>
      <td class="desc-cell">${t.description}</td>
      <td class="${t.expenditure > 0 ? 'type-exp' : ''}">${t.expenditure > 0 ? kshFull(t.expenditure) : '-'}</td>
      <td class="${t.revenue > 0 ? 'type-rev' : ''}">${t.revenue > 0 ? kshFull(t.revenue) : '-'}</td>
      <td class="pm-cell">${t.paymentMethod}</td>
    </tr>
  `).join('');
}

// ========== INSIGHTS ==========
function renderInsights() {
  const months = ['January','February','March','April'];
  const mStats = months.map(m => {
    const txs = transactions.filter(t=>t.month===m);
    const exp = txs.reduce((s,t)=>s+t.expenditure,0);
    const rev = txs.reduce((s,t)=>s+t.revenue,0);
    return { month: m, exp, rev, net: rev-exp, txCount: txs.length };
  });

  document.getElementById('monthly-compare').innerHTML = mStats.map(s => `
    <div class="month-card ${currentMonth===s.month?'sel':''}" onclick="setMonth('${s.month}', null); document.querySelectorAll('.month-card').forEach(e=>e.classList.remove('sel')); this.classList.add('sel')">
      <h4>${s.month}</h4>
      <div class="mval" style="color:var(--red)">${ksh(s.exp)}</div>
      <div class="msub">Spent · ${ksh(s.rev)} received</div>
      <div class="mnet ${s.net>=0?'pos':'neg'}">${s.net>=0?'+':''}${ksh(s.net)}</div>
    </div>
  `).join('');

  const txs = getFilteredTx();
  const cats = getCatSummary(txs);

  const topSpend = Object.entries(cats).sort((a,b)=>b[1].exp-a[1].exp).slice(0,8);
  document.getElementById('top-spend-list').innerHTML = topSpend.map(([cat,data],i) => `
    <div class="insight-item">
      <div class="insight-rank ${i===0?'top1':''}">${i+1}</div>
      <div class="insight-body">
        <div class="insight-name">${cat}</div>
        <div class="insight-sub">${data.count} transactions</div>
      </div>
      <div class="insight-val" style="color:var(--red)">${ksh(data.exp)}</div>
    </div>
  `).join('');

  const topRev = Object.entries(cats).filter(([,v])=>v.rev>0).sort((a,b)=>b[1].rev-a[1].rev).slice(0,8);
  document.getElementById('top-rev-list').innerHTML = topRev.map(([cat,data],i) => `
    <div class="insight-item">
      <div class="insight-rank ${i===0?'top1':''}">${i+1}</div>
      <div class="insight-body">
        <div class="insight-name">${cat}</div>
        <div class="insight-sub">${data.count} sources</div>
      </div>
      <div class="insight-val" style="color:var(--green)">${ksh(data.rev)}</div>
    </div>
  `).join('');

  // Daily avg
  const days = getDaysInPeriod(txs);
  const totalExp = txs.reduce((s,t)=>s+t.expenditure,0);
  const totalRev = txs.reduce((s,t)=>s+t.revenue,0);
  document.getElementById('daily-avg-list').innerHTML = `
    <div class="insight-item"><div class="insight-body"><div class="insight-name">Avg Daily Spend</div><div class="insight-sub">Over ${days} days</div></div><div class="insight-val" style="color:var(--red)">${ksh(totalExp/days)}</div></div>
    <div class="insight-item"><div class="insight-body"><div class="insight-name">Avg Daily Revenue</div><div class="insight-sub">Over ${days} days</div></div><div class="insight-val" style="color:var(--green)">${ksh(totalRev/days)}</div></div>
    <div class="insight-item"><div class="insight-body"><div class="insight-name">Total Transactions</div><div class="insight-sub">All records</div></div><div class="insight-val">${txs.length}</div></div>
    <div class="insight-item"><div class="insight-body"><div class="insight-name">Avg Tx Amount</div><div class="insight-sub">Expenditure only</div></div><div class="insight-val">${ksh(totalExp/Math.max(1,txs.filter(t=>t.expenditure>0).length))}</div></div>
  `;

  // MoM
  const momHtml = mStats.map((s,i) => {
    if (i === 0) return `<div class="insight-item"><div class="insight-body"><div class="insight-name">${s.month}</div><div class="insight-sub">Baseline month</div></div><div class="insight-val">${ksh(s.exp)}</div></div>`;
    const prev = mStats[i-1];
    const pct = ((s.exp - prev.exp)/Math.max(1,prev.exp)*100).toFixed(1);
    const dir = s.exp <= prev.exp;
    return `<div class="insight-item"><div class="insight-body"><div class="insight-name">${s.month}</div><div class="insight-sub">vs ${prev.month.slice(0,3)}: <span style="color:${dir?'var(--green)':'var(--red)'}">${dir?'':'+'}{${pct}}%</span></div></div><div class="insight-val" style="color:${dir?'var(--green)':'var(--red)'}">${ksh(s.exp)}</div></div>`;
  }).join('').replace(/{/g,'').replace(/}/g,'');
  document.getElementById('mom-list').innerHTML = momHtml;
}

// ========== ADD TRANSACTION ==========
function addTransaction() {
  const date = document.getElementById('add-date').value;
  const month = document.getElementById('add-month').value;
  const category = document.getElementById('add-category').value;
  const description = document.getElementById('add-desc').value.trim() || category;
  const exp = parseFloat(document.getElementById('add-exp').value) || 0;
  const rev = parseFloat(document.getElementById('add-rev').value) || 0;
  const tc = parseFloat(document.getElementById('add-tc').value) || 0;
  const pm = document.getElementById('add-pm').value;

  if (!date) { showToast('⚠️ Please enter a date'); return; }
  if (exp === 0 && rev === 0) { showToast('⚠️ Please enter expenditure or revenue'); return; }

  const newTx = {
    id: transactions.length + 1,
    date, month, category, description,
    expenditure: exp, revenue: rev, transactionCost: tc,
    paymentMethod: pm,
    type: exp > 0 && rev === 0 ? 'Expenditure' : 'Revenue'
  };

  transactions.unshift(newTx);
  newlyAdded.unshift(newTx);
  showToast('✅ Transaction added successfully!');
  clearForm();
  renderAdded();
}

function clearForm() {
  ['add-desc','add-exp','add-rev','add-tc'].forEach(id => { document.getElementById(id).value = ''; });
}

function renderAdded() {
  const el = document.getElementById('added-tbody');
  if (!newlyAdded.length) {
    el.innerHTML = '<tr><td colspan="6" style="text-align:center;color:var(--text3);padding:24px;">No transactions added yet</td></tr>';
    return;
  }
  el.innerHTML = newlyAdded.slice(0,20).map(t => `
    <tr>
      <td class="date-cell">${t.date}</td>
      <td><span class="cat-badge" style="background:${catColor(t.category)}22;color:${catColor(t.category)}">${t.category}</span></td>
      <td class="desc-cell">${t.description}</td>
      <td class="${t.expenditure > 0 ? 'type-exp' : ''}">${t.expenditure > 0 ? kshFull(t.expenditure) : '-'}</td>
      <td class="${t.revenue > 0 ? 'type-rev' : ''}">${t.revenue > 0 ? kshFull(t.revenue) : '-'}</td>
      <td><button class="btn btn-danger" style="padding:4px 10px;font-size:11px" onclick="removeAdded(${t.id})">Remove</button></td>
    </tr>
  `).join('');
}

function removeAdded(id) {
  transactions = transactions.filter(t => t.id !== id);
  newlyAdded = newlyAdded.filter(t => t.id !== id);
  renderAdded();
  showToast('🗑️ Transaction removed');
}

function showToast(msg) {
  const t = document.getElementById('toast');
  t.textContent = msg;
  t.classList.add('show');
  setTimeout(() => t.classList.remove('show'), 3000);
}

// ========== INIT ==========
renderOverview();
